#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,t;
    bool operator<(const node&b)const
    {
        if(t==b.t)
        {
            return x<b.x;
        }
        return t<b.t;
    }
}a[100010];
multiset<node> s;
multiset<int> ans;
int calc(node a,node b)
{
    return abs(a.x-b.x)/abs(a.t-b.t);
}
void add(node v)
{
    s.insert(v);
    auto it=s.lower_bound(v),it1=it,it2=it;
    auto pre=(--it),nxt=(++it1);
    if(it2!=s.begin()&&it2!=s.end()&&nxt!=s.end())
    {
        ans.erase(ans.lower_bound(calc(*pre,*nxt)));
    }
    if(it2!=s.begin())
    {
        ans.insert(calc(*pre,v));
    }
    if(it2!=s.end()&&nxt!=s.end())
    {
        ans.insert(calc(v,*nxt));
    }
}
void del(node v)
{
    auto it=s.lower_bound(v),it1=it,it2=it;
    auto pre=(--it),nxt=(++it1);
    if(it2!=s.begin()&&it2!=s.end()&&nxt!=s.end())
    {
        ans.insert(calc(*pre,*nxt));
    }
    if(it2!=s.begin())
    {
        ans.erase(ans.lower_bound(calc(*pre,v)));
    }
    if(it2!=s.end()&&nxt!=s.end())
    {
        ans.erase(ans.lower_bound(calc(v,*nxt)));
    }
    s.erase(s.lower_bound(v));
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int x,t;
        scanf("%d%d",&x,&t);
        a[i].x=x;
        a[i].t=t;
        s.insert((node){x,t});
    }
    node pre;
    int flag=0;
    for(auto i:s)
    {
        if(flag==0)
        {
            pre=i;
            flag=1;
            continue;
        }
        ans.insert(calc(pre,i));
        pre=i;
    }
    while(m--)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        node now=a[u];
        now.t=v;
        del(a[u]);
        add(now);
        printf("%d\n",(*ans.rbegin()));
        del(now);
        add(a[u]);
    }
    return 0;
}
